PRAGMA foreign_keys=OFF;
BEGIN TRANSACTION;
CREATE TABLE spatial_ref_sys(srid INTEGER PRIMARY KEY,sr_name TEXT, auth_name TEXT,auth_srid INTEGER,srtext TEXT,sr_xytol REAL,sr_ztol REAL );
