CREATE TABLE TB_DOMAIN (ID INTEGER PRIMARY KEY not null, ACTIVE INTEGER(1) default 1 not null, CAPTION VARCHAR2(255) not null, READ_ONLY INTEGER(1) default 0 not null, TABLE_DOES_NOT_EXIST INTEGER(1) default 0 not null, TABLE_NAME VARCHAR2(30) not null, constraint TB_DOMAIN_CAPTION_U unique (CAPTION), constraint TB_DOMAIN_TABLENAME_U unique (TABLE_NAME));
CREATE TABLE TB_INFO (ID INTEGER PRIMARY KEY not null, COMMENTARY VARCHAR2(255), PARAM VARCHAR2(255) not null, VALUE_CHAR VARCHAR2(255), VALUE_NUMBER REAL(20,8), constraint TB_INFO_U unique (PARAM));
CREATE TABLE TB_VERSION (ID INTEGER PRIMARY KEY not null, DATA_MODEL_CODE VARCHAR2(12), MODULE_NAME VARCHAR2(255), VERSION_DATE DATETIME_as_text not null, VERSION_NUMBER VARCHAR2(10) not null, CAPTION VARCHAR2(255), MIN_VERSION_REASON VARCHAR2(4000), MIN_VERSION VARCHAR2(10));
CREATE TABLE fdo_columns( f_table_name TEXT, f_column_name TEXT, f_column_desc TEXT, fdo_data_type INTEGER, fdo_data_details INTEGER, fdo_data_length INTEGER, fdo_data_precision INTEGER, fdo_data_scale INTEGER);
