CREATE TABLE TB_DIMENSION (ID INTEGER PRIMARY KEY not null, ABSCISSA_DIM_LABEL_DEF_ID INTEGER(18), ABSCISSA_END_LABEL_DEF_ID INTEGER(18), ABSCISSA_START_LABEL_DEF_ID INTEGER(18), ALIGNED_DIM_LABEL_DEF_ID INTEGER(18), AUTO_ABSCISSA_END INTEGER(1), AUTO_ABSCISSA_START INTEGER(1), DIMENSION_F_CLASS_ID INTEGER(10) not null, LABEL_F_CLASS_ID INTEGER(10) not null, LINE_F_CLASS_ID INTEGER(10) not null, ORDINATE_DIM_LABEL_DEF_ID INTEGER(18), POINT_F_CLASS_ID INTEGER(10) not null);
