CREATE TRIGGER CONSTRUCT_BI_FID before insert on CONSTRUCT for each row
when new.FID = -1
begin
  update TB_SEQUENCE_EMULATION set NEXT_VALUE = NEXT_VALUE+1 where SEQUENCE_NAME = 'TB_UFID_S';

    values ((select NEXT_VALUE-1 from TB_SEQUENCE_EMULATION where SEQUENCE_NAME = 'TB_UFID_S'));
  select raise(ignore);
end;
CREATE TRIGGER CONSTRUCT_AI_FID after insert on CONSTRUCT for each row
begin
  delete from TB_UFID where FID = new.FID and F_CLASS_ID = 1;

    values (new.FID, 1, current_timestamp, 0);
end;
CREATE TRIGGER CONSTRUCT_BU_FID before update of FID on CONSTRUCT for each row
when new.fid != old.fid
begin
  select raise(ROLLBACK, 'FID of feature class CONSTRUCT cannot be changed.');
end;
CREATE TRIGGER CONSTRUCT_AU_FID after update on CONSTRUCT for each row
begin
  update TB_UFID set TOUCH_TS = current_timestamp where FID = new.FID;
end;
CREATE TRIGGER CONSTRUCT_AD_FID after delete on CONSTRUCT for each row
begin
  update TB_UFID set TOUCH_TS = current_timestamp where FID = old.FID;
end;
CREATE TRIGGER CONSTRUCT_LINES_AI_FID after insert on CONSTRUCT_LINES for each row
begin
  delete from TB_UFID where FID = new.FID and F_CLASS_ID = 2;

    values (new.FID, 2, current_timestamp, 0);
end;
CREATE TRIGGER CONSTRUCT_LINES_BU_FID before update of FID on CONSTRUCT_LINES for each row
when new.fid != old.fid
begin
  select raise(ROLLBACK, 'FID of feature class CONSTRUCT_LINES cannot be changed.');
end;
CREATE TRIGGER CONSTRUCT_LINES_AU_FID after update on CONSTRUCT_LINES for each row
begin
  update TB_UFID set TOUCH_TS = current_timestamp where FID = new.FID;
end;
CREATE TRIGGER CONSTRUCT_LINES_AD_FID after delete on CONSTRUCT_LINES for each row
begin
