INSERT INTO TB_EXPLORER_STMT VALUES(2,1,NULL,'Autodesk, Inc.','Topic.ico',1,0,NULL,'SubTopics',0,'Caption','SELECT ID, Caption, Name FROM TB_TOPIC WHERE TOPIC_ID={0} ORDER BY Caption','Topic.gif');
INSERT INTO TB_EXPLORER_STMT VALUES(3,1,NULL,'Autodesk, Inc.',NULL,1,0,NULL,'FeatureClasses',1,'Caption','SELECT F_CLASS_ID,Caption, F_CLASS_NAME,  CASE  WHEN  F_CLASS_TYPE = ''P'' THEN ''Point.ico'' WHEN F_CLASS_TYPE = ''L'' THEN ''LineString.ico'' WHEN F_CLASS_TYPE = ''O'' THEN ''Polygon.ico'' WHEN F_CLASS_TYPE = ''A'' THEN ''Label.ico'' WHEN F_CLASS_TYPE = ''C'' THEN ''Collection.ico'' WHEN F_CLASS_TYPE = ''T'' THEN ''Attribute.ico'' WHEN F_CLASS_TYPE = ''E'' THEN ''Centroid.ico'' WHEN F_CLASS_TYPE = ''S'' THEN ''CompoundPolygon.ico'' WHEN F_CLASS_TYPE = ''I'' THEN ''CompoundLineString.ico'' WHEN F_CLASS_TYPE = ''M'' THEN ''Dimension.ico'' ELSE F_CLASS_TYPE END as Icon, CASE WHEN F_CLASS_TYPE =  ''P'' THEN  ''Autodesk.Map.IM.Data.FeatureClassType.Point'' WHEN  F_CLASS_TYPE =  ''L'' THEN  ''Autodesk.Map.IM.Data.FeatureClassType.Linestring'' WHEN  F_CLASS_TYPE =  ''O'' THEN  ''Autodesk.Map.IM.Data.FeatureClassType.Polygon'' WHEN  F_CLASS_TYPE =  ''A'' THEN  ''Autodesk.Map.IM.Data.FeatureClassType.Label'' WHEN  F_CLASS_TYPE =  ''C'' THEN  ''Autodesk.Map.IM.Data.FeatureClassType.Collection'' WHEN  F_CLASS_TYPE =  ''T'' THEN  ''Autodesk.Map.IM.Data.FeatureClassType.Attribute'' WHEN  F_CLASS_TYPE =  ''E'' THEN  ''Autodesk.Map.IM.Data.FeatureClassType.Centroid'' WHEN  F_CLASS_TYPE =  ''S'' THEN  ''Autodesk.Map.IM.Data.FeatureClassType.CompoundPolygon'' WHEN  F_CLASS_TYPE =  ''I'' THEN  ''Autodesk.Map.IM.Data.FeatureClassType.CompoundLineString'' WHEN  F_CLASS_TYPE =  ''M'' THEN  ''Autodesk.Map.IM.Data.FeatureClassType.Dimension'' ELSE  F_CLASS_TYPE  END as Type FROM TB_DICTIONARY WHERE PARENT_F_CLASS_ID IS NULL AND TOPIC_ID={0} ORDER BY Caption',NULL);
INSERT INTO TB_EXPLORER_STMT VALUES(4,1,NULL,'Autodesk, Inc.',NULL,1,1,NULL,'SubFeatureClasses',0,'Caption','SELECT F_CLASS_ID, Caption, F_CLASS_NAME, CASE WHEN F_CLASS_TYPE = ''P'' THEN ''Point.ico'' WHEN F_CLASS_TYPE = ''L'' THEN ''LineString.ico'' WHEN F_CLASS_TYPE = ''O'' THEN ''Polygon.ico'' WHEN F_CLASS_TYPE = ''A'' THEN ''Label.ico'' WHEN F_CLASS_TYPE = ''C'' THEN ''Collection.ico'' WHEN F_CLASS_TYPE = ''T'' THEN ''Attribute.ico'' WHEN F_CLASS_TYPE = ''E'' THEN ''Centroid.ico'' WHEN F_CLASS_TYPE = ''S'' THEN ''CompoundPolygon.ico'' WHEN F_CLASS_TYPE = ''I'' THEN ''CompoundLineString.ico'' WHEN F_CLASS_TYPE = ''M'' THEN ''Dimension.ico'' ELSE F_CLASS_TYPE END as Icon, CASE WHEN F_CLASS_TYPE = ''P'' THEN ''Autodesk.Map.IM.Data.FeatureClassType.Point'' WHEN F_CLASS_TYPE = ''L'' THEN ''Autodesk.Map.IM.Data.FeatureClassType.LineString'' WHEN F_CLASS_TYPE = ''O'' THEN ''Autodesk.Map.IM.Data.FeatureClassType.Polygon'' WHEN F_CLASS_TYPE = ''A'' THEN ''Autodesk.Map.IM.Data.FeatureClassType.Label'' WHEN F_CLASS_TYPE = ''C'' THEN ''Autodesk.Map.IM.Data.FeatureClassType.Collection'' WHEN F_CLASS_TYPE = ''T'' THEN ''Autodesk.Map.IM.Data.FeatureClassType.Attribute'' WHEN F_CLASS_TYPE = ''E'' THEN ''Autodesk.Map.IM.Data.FeatureClassType.Centroid'' WHEN F_CLASS_TYPE = ''S'' THEN ''Autodesk.Map.IM.Data.FeatureClassType.CompoundPolygon'' WHEN F_CLASS_TYPE = ''I'' THEN ''Autodesk.Map.IM.Data.FeatureClassType.CompoundLineString'' WHEN F_CLASS_TYPE = ''M'' THEN ''Autodesk.Map.IM.Data.FeatureClassType.Dimension'' ELSE F_CLASS_TYPE END as Type, CASE WHEN D.F_CLASS_ID IN (SELECT CHILD_F_CLASS_ID FROM TB_COMPOUND) THEN 1 ELSE null END  AS COMPOUND FROM TB_DICTIONARY D WHERE PARENT_F_CLASS_ID={0} ORDER BY Compound, Caption',NULL);
INSERT INTO TB_EXPLORER_STMT VALUES(5,1,NULL,'Autodesk, Inc.','LabelDefinition.ico',1,1,NULL,'LabelDefinitions',1,'Caption','SELECT LD.ID, LD.Name FROM TB_LABEL_DEF LD, TB_LABEL L WHERE LD.LABEL_ID=L.ID AND L.TBL_F_CLASS_ID={0} ORDER BY LD.Name','LabelDefinition.gif');
INSERT INTO TB_EXPLORER_STMT VALUES(6,1,2,'Autodesk, Inc.','DomainTable.ico',1,0,NULL,'Domains',0,'Caption','SELECT ID, Caption, Table_Name FROM TB_DOMAIN ORDER BY Caption','DomainTable.gif');
INSERT INTO TB_EXPLORER_STMT VALUES(7,1,3,'Autodesk, Inc.',NULL,1,0,NULL,'Topologies',0,'Name','SELECT ID, Caption, NULL, CASE WHEN INITIALIZED = 1 THEN ( CASE WHEN TYPE = ''A'' THEN ''AreaTopologyInit.ico'' WHEN TYPE =''N'' THEN ''NetTopologyInit.ico'' WHEN TYPE = ''L'' THEN ''NetTopologyInit.ico'' ELSE TYPE END ) ELSE ( CASE WHEN TYPE = ''A'' THEN ''AreaTopology.ico'' WHEN TYPE = ''N'' THEN ''NetTopology.ico'' WHEN TYPE = ''L'' THEN ''NetTopology.ico'' ELSE TYPE END ) END as Icon, CASE WHEN TYPE = ''A'' THEN ''Autodesk.Map.IM.Data.TopologyType.Area'' WHEN TYPE = ''N'' THEN ''Autodesk.Map.IM.Data.TopologyType.Net'' WHEN TYPE = ''L'' THEN ''Autodesk.Map.IM.Data.TopologyType.Logical'' ELSE TYPE END as Type FROM TB_TOPOLOGY ORDER BY Caption',NULL);
INSERT INTO TB_EXPLORER_STMT VALUES(8,1,4,'Autodesk, Inc.',NULL,1,0,NULL,'Intersections',0,'Name','SELECT ID, Caption, Name, CASE WHEN TYPE = ''OO'' THEN ''IntersectionPolygonPolygon.ico'' WHEN TYPE = ''OL'' THEN ''IntersectionPolygonLine.ico'' WHEN TYPE = ''LL'' THEN ''IntersectionLineLine.ico'' WHEN TYPE = ''OP'' THEN ''IntersectionPolygonPoint.ico'' WHEN TYPE = ''LP'' THEN ''IntersectionLinePoint.ico'' ELSE TYPE END as Icon, CASE WHEN TYPE = ''OO'' THEN ''Autodesk.Map.IM.Data.IntersectionType.PolygonPolygon'' WHEN TYPE = ''OL'' THEN ''Autodesk.Map.IM.Data.IntersectionType.PolygonLine'' WHEN TYPE = ''LL'' THEN ''Autodesk.Map.IM.Data.IntersectionType.LineLine'' WHEN TYPE = ''OP'' THEN ''Autodesk.Map.IM.Data.IntersectionType.PolygonPoint'' WHEN TYPE = ''LP'' THEN ''Autodesk.Map.IM.Data.IntersectionType.LinePoint'' ELSE TYPE END as Type FROM TB_INTERSECTION ORDER BY Caption',NULL);
INSERT INTO TB_EXPLORER_STMT VALUES(9,1,5,'Autodesk, Inc.','SystemTable.ico',1,0,NULL,'System Tables',0,'Table_Name','SELECT tbl_name as key, tbl_name as caption, tbl_name as table_name FROM sqlite_master where type=''table'' AND tbl_name LIKE ''TB_%'' order by tbl_name','SystemTable.gif');
