INSERT INTO TB_RPT_FUNCTION VALUES(3,unistr('Dim valueToFormat as string = Me.FunctionParameters.Item(0)\u000d\u000aDim format as string = Me.FunctionParameters.Item(1)\u000d\u000aDim digit as integer  = format.Substring(format.LastIndexOf("D")+1).Length-1\u000d\u000aIf me.Connection.Identifier.DatabaseType = Autodesk.Map.IM.Data.Provider.ConnectionIdentifier.Oracle.Type Then\u000d\u000a    COMMON_TO_CHAR = "to_char(" & valueToFormat & ",  " & format & ")"\u000d\u000aElseIf me.Connection.Identifier.DatabaseType = Autodesk.Map.IM.Data.Provider.ConnectionIdentifier.SqlServer.Type Then\u000d\u000a    COMMON_TO_CHAR = "str(" & valueToFormat & ",  " & valueToFormat.Length & ",  " & digit & ")"\u000d\u000aElse\u000d\u000a    COMMON_TO_CHAR = "round(" & valueToFormat & ",  " & digit & ")"\u000d\u000aEnd If'),NULL,0,'COMMON_TO_CHAR',1);
INSERT INTO TB_RPT_FUNCTION VALUES(4,unistr('Dim FromYear, FromMon, FromDay, FromHour, FromMin, FromSec as integer\u000d\u000aFromYear = System.Convert.ToInt32(Me.Parameter("FromYear"))\u000d\u000aFromMon =System.Convert.ToInt32(Me.Parameter("FromMonth"))\u000d\u000aFromDay = System.Convert.ToInt32(Me.Parameter("FromDay"))\u000d\u000aFromHour =System.Convert.ToInt32(Me.Parameter("FromHour"))\u000d\u000aFromMin = System.Convert.ToInt32(Me.Parameter("FromMinute"))\u000d\u000aFromSec = System.Convert.ToInt32(Me.Parameter("FromSecond"))\u000d\u000aDim FromD as string\u000d\u000aFromD = string.Format("''{0:D4}-{1:D2}-{2:D2} {3:D2}:{4:D2}:{5:D2}''", FromYear, FromMon, FromDay, FromHour, FromMin, FromSec)\u000d\u000aIf me.Connection.Identifier.DatabaseType = Autodesk.Map.IM.Data.Provider.ConnectionIdentifier.Oracle.Type Then\u000d\u000a    FromDate  = "To_Date(" & FromD & ", ''YYYY-MM-DD HH24:MI:SS'')"\u000d\u000aelse\u000d\u000a    FromDate = FromD \u000d\u000aend if'),NULL,0,'FROMDATE',1);
INSERT INTO TB_RPT_FUNCTION VALUES(5,unistr('If me.Connection.Identifier.DatabaseType = Autodesk.Map.IM.Data.Provider.ConnectionIdentifier.Oracle.Type then\u000d\u000a    dim oracleIdentifier as  Autodesk.Map.IM.Data.Provider.ConnectionIdentifier.Oracle\u000d\u000a    oracleIdentifier = me.Connection.Identifier\u000d\u000a    GETDATASOURCE = oracleIdentifier.ServiceName\u000d\u000aelse\u000d\u000a    GETDATASOURCE = ""\u000d\u000aend if\u000d\u000a'),NULL,0,'GETDATASOURCE',1);
