INSERT INTO TB_RPT_FUNCTION VALUES(51,unistr('Dim EndYear, EndMon, EndDay, EndHour, EndMin, EndSec as integer\u000d\u000aEndYear = System.Convert.ToInt32(Me.Parameter("ToYear"))\u000d\u000aEndMon =System.Convert.ToInt32(Me.Parameter("ToMonth"))\u000d\u000aEndDay = System.Convert.ToInt32(Me.Parameter("ToDay"))\u000d\u000aEndHour =System.Convert.ToInt32(Me.Parameter("ToHour"))\u000d\u000aEndMin = System.Convert.ToInt32(Me.Parameter("ToMinute"))\u000d\u000aEndSec = System.Convert.ToInt32(Me.Parameter("ToSecond"))\u000d\u000aDim EndD as string\u000d\u000aEndD = string.Format("''{0:D4}-{1:D2}-{2:D2} {3:D2}:{4:D2}:{5:D2}''", EndYear, EndMon, EndDay, EndHour, EndMin, EndSec)\u000d\u000aIf me.Connection.Identifier.DatabaseType = Autodesk.Map.IM.Data.Provider.ConnectionIdentifier.Oracle.Type Then\u000d\u000a    EndDate  = "To_Date(" & EndD & ", ''YYYY-MM-DD HH24:MI:SS'')"\u000d\u000aelse\u000d\u000a    EndDate = EndD \u000d\u000aend if'),NULL,0,'ENDDATE',8);
