INSERT INTO TB_RPT_FUNCTION VALUES(54,unistr('Dim valueToFormat as string = Me.FunctionParameters.Item(0)\u000d\u000aDim format as string = Me.FunctionParameters.Item(1)\u000d\u000aDim digit as integer  = format.Substring(format.LastIndexOf("D")+1).Length-1\u000d\u000aIf me.Connection.Identifier.DatabaseType = Autodesk.Map.IM.Data.Provider.ConnectionIdentifier.Oracle.Type Then\u000d\u000a    COMMON_TO_CHAR = "to_char(" & valueToFormat & ",  " & format & ")"\u000d\u000aElseIf me.Connection.Identifier.DatabaseType = Autodesk.Map.IM.Data.Provider.ConnectionIdentifier.SqlServer.Type Then\u000d\u000a    COMMON_TO_CHAR = "str(" & valueToFormat & ",  " & valueToFormat.Length & ",  " & digit & ")"\u000d\u000aElse\u000d\u000a    COMMON_TO_CHAR = "round(" & valueToFormat & ",  " & digit & ")"\u000d\u000aEnd If'),NULL,0,'COMMON_TO_CHAR',9);
