INSERT INTO TB_RPT_FUNCTION VALUES(56,unistr('If me.Connection.Identifier.DatabaseType = Autodesk.Map.IM.Data.Provider.ConnectionIdentifier.Oracle.Type then\u000d\u000a    dim oracleIdentifier as  Autodesk.Map.IM.Data.Provider.ConnectionIdentifier.Oracle\u000d\u000a    oracleIdentifier = me.Connection.Identifier\u000d\u000a    GETDATASOURCE = oracleIdentifier.ServiceName\u000d\u000aelse\u000d\u000a    GETDATASOURCE = ""\u000d\u000aend if\u000d\u000a'),NULL,0,'GETDATASOURCE',9);
